import React, { useState } from "react";
import api from "../../api";

const emailTemplates = {
  promo: {
    name: "🎁 Khuyến mãi",
    html: `
      <h1 style="color:#e06c7f;">🌸 Ưu đãi đặc biệt!</h1>
      <p>Giảm <strong>20%</strong> cho đơn hàng hôm nay 💐</p>
    `,
  },
  holiday: {
    name: "🎄 Dịp lễ / năm mới",
    html: `
      <h1 style="color:#e06c7f;">🎄 Chúc mừng năm mới!</h1>
      <p>Hoa tươi giảm giá 15% tại DTP Flower Shop</p>
    `,
  },
  birthday: {
    name: "🎂 Sinh nhật",
    html: `
      <h1 style="color:#e06c7f;">🎂 Happy Birthday!</h1>
      <p>🎁 Tặng voucher 10% cho ngày đặc biệt của bạn 💌</p>
    `,
  },
};

const SendEmailPage = () => {
  const [subject, setSubject] = useState("");
  const [group, setGroup] = useState("all");
  const [template, setTemplate] = useState("promo");
  const [customHtml, setCustomHtml] = useState("");
  const [sending, setSending] = useState(false);
  const [message, setMessage] = useState("");

  const handleSend = async () => {
    if (!subject.trim()) {
      return setMessage("❌ Subject không được để trống.");
    }

    setSending(true);
    setMessage("");

    try {
      const htmlContent =
        template === "custom"
          ? customHtml
          : emailTemplates[template].html;

      const res = await api.post("/email/send", {
        subject,
        group,
        html: htmlContent,
        templateName: template,
      });

      setMessage(res.data.message || "📩 Gửi email thành công!");
    } catch (err) {
      console.error(err);
      setMessage("❌ Gửi email thất bại.");
    }

    setSending(false);
  };

  const previewHtml =
    template === "custom"
      ? customHtml || "<p>Nhập nội dung HTML...</p>"
      : emailTemplates[template].html;

  return (
    <div className="p-8">
      <h1 className="text-3xl font-bold text-[#e06c7f] mb-8">
        📩 Gửi Email Marketing
      </h1>

      <div className="bg-white p-6 rounded-xl shadow-lg max-w-3xl">
        {/* Subject */}
        <label className="font-medium">Tiêu đề Email</label>
        <input
          className="w-full border p-3 rounded-lg mb-4"
          placeholder="Nhập tiêu đề email"
          value={subject}
          onChange={(e) => setSubject(e.target.value)}
        />

        {/* Group */}
        <label className="font-medium">Gửi đến nhóm:</label>
        <select
          className="w-full border p-3 rounded-lg mb-4"
          value={group}
          onChange={(e) => setGroup(e.target.value)}
        >
          <option value="all">📢 Tất cả khách hàng</option>
          <option value="user">👤 Người dùng có tài khoản</option>
          <option value="newsletter">📰 Người đăng ký nhận tin</option>
          <option value="vip">👑 Khách hàng VIP</option>
          <option value="admin">🛠 Admin</option>
        </select>

        {/* Template */}
        <label className="font-medium">Chọn mẫu email:</label>
        <select
          className="w-full border p-3 rounded-lg mb-4"
          value={template}
          onChange={(e) => setTemplate(e.target.value)}
        >
          {Object.entries(emailTemplates).map(([key, t]) => (
            <option key={key} value={key}>
              {t.name}
            </option>
          ))}
          <option value="custom">✍️ Tự nhập nội dung</option>
        </select>

        {/* Custom HTML */}
        {template === "custom" && (
          <textarea
            className="w-full border p-3 rounded-lg mb-4 h-40"
            placeholder="Nhập HTML..."
            value={customHtml}
            onChange={(e) => setCustomHtml(e.target.value)}
          />
        )}

        {/* Send button */}
        <button
          onClick={handleSend}
          disabled={sending}
          className="w-full py-3 bg-[#e06c7f] hover:bg-[#d35d75] text-white font-semibold rounded-lg"
        >
          {sending ? "Đang gửi..." : "📨 Gửi Email"}
        </button>

        {message && (
          <div
            className={`mt-4 p-3 rounded-lg ${
              message.startsWith("❌")
                ? "bg-red-100 text-red-700 border border-red-300"
                : "bg-green-100 text-green-700 border border-green-300"
            }`}
          >
            {message}
          </div>
        )}
      </div>

      {/* Preview */}
      <div className="mt-8 p-6 bg-[#faf8f6] border border-[#f0e8e3] rounded-xl">
        <h2 className="text-xl font-semibold mb-3">📌 Preview email</h2>

        <div
          className="border bg-white rounded-lg p-5 shadow-sm"
          dangerouslySetInnerHTML={{ __html: previewHtml }}
        />
      </div>
    </div>
  );
};

export default SendEmailPage;
